const item = $input.first().json;

function extractJson(value) {
  if (value && typeof value === 'object' && (value.cleaned_transcript_markdown || value.output_markdown || value.document_title)) {
    return value;
  }

  const raw = String(value?.response || value?.text || value?.output || value?.result || value?.message?.content || '').trim();
  if (!raw) throw new Error('AI did not return text or structured JSON.');

  const cleaned = raw
    .replace(/^```[a-zA-Z]*\n?/, '')
    .replace(/```$/, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (_) {
    const firstBrace = cleaned.indexOf('{');
    const lastBrace = cleaned.lastIndexOf('}');
    if (firstBrace >= 0 && lastBrace > firstBrace) {
      return JSON.parse(cleaned.slice(firstBrace, lastBrace + 1));
    }
  }

  throw new Error('AI did not return usable JSON. Rerun the workflow or use a model that supports JSON output.');
}

function asList(value, fallback) {
  if (Array.isArray(value)) {
    const cleaned = value.map((item) => String(item).trim()).filter(Boolean);
    if (cleaned.length) return cleaned;
  }
  if (typeof value === 'string' && value.trim()) {
    return value.split('\n').map((item) => item.replace(/^[-*]\s*/, '').trim()).filter(Boolean);
  }
  return fallback;
}

function bulletList(items) {
  return asList(items, ['Review and customize this output.']).map((item) => '- ' + item).join('\n');
}

function removeTranscriptJunk(text) {
  return String(text || '')
    .replace(/\b(um|uh|you know)\b[,.]?\s*/gi, '')
    .replace(/^#\s+.+\n+/, '')
    .replace(/\btrustable\b/gi, 'reliable')
    .replace(/\s{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const parsed = extractJson(item);
const cleanedTranscript = removeTranscriptJunk(parsed.cleaned_transcript_markdown || parsed.output_markdown || '');

if (!cleanedTranscript) {
  throw new Error('AI response did not include cleaned_transcript_markdown.');
}

const keyTakeaways = asList(parsed.key_takeaways, ['The transcript was cleaned for readability.']);
const repurposingIdeas = asList(parsed.repurposing_ideas, ['Turn this into a short post.', 'Use it as a draft section.', 'Save it as source material.']);
const cleanupNotes = asList(parsed.cleanup_notes, ['Removed filler and improved readability while preserving meaning.']);
const needsHumanReview = asList(parsed.needs_human_review, ['Check names, numbers, quotes, claims, and technical details before publishing.']);
const nextSteps = asList(parsed.next_steps, ['Review the cleaned transcript.', 'Add missing context.', 'Repurpose the strongest section.']);

const markdown = [
  '## Cleaned Transcript',
  cleanedTranscript,
  '',
  '## Key Takeaways',
  bulletList(keyTakeaways),
  '',
  '## Repurposing Ideas',
  bulletList(repurposingIdeas),
  '',
  '## Cleanup Notes',
  bulletList(cleanupNotes),
  '',
  '## Needs Human Review',
  bulletList(needsHumanReview)
].join('\n');

return [{
  json: {
    workflow_name: 'GP-WF-005 - YouTube Transcript Cleaner',
    created_at: new Date().toISOString(),
    document_title: String(parsed.document_title || 'Cleaned Transcript').trim(),
    summary: String(parsed.summary || 'Cleaned a rough transcript into readable Markdown.').trim(),
    output_markdown: markdown,
    cleaned_transcript_markdown: cleanedTranscript,
    key_takeaways: keyTakeaways,
    repurposing_ideas: repurposingIdeas,
    cleanup_notes: cleanupNotes,
    needs_human_review: needsHumanReview,
    next_steps: nextSteps,
    review_note: String(parsed.review_note || 'Review facts, names, claims, and any technical details before publishing.').trim()
  }
}];

const today = new Date();
const date = today.toISOString().slice(0, 10);
const nextSteps = Array.isArray($json.next_steps) ? $json.next_steps : [];

const body = [
  `# ${$json.document_title || 'Cleaned Transcript'}`,
  '',
  `Created: ${date}`,
  'Workflow: GP-WF-005 - YouTube Transcript Cleaner',
  '',
  '## Summary',
  $json.summary || 'No summary returned.',
  '',
  $json.output_markdown || '',
  '',
  '## Next Steps',
  ...(nextSteps.length ? nextSteps.map((step) => `- ${step}`) : ['- Review and customize this output.']),
  '',
  '## Human Review Note',
  $json.review_note || 'Review this output before using it.',
  '',
  'Source: GetPrompting Free Workflow Library'
].join('\n');

return [{
  json: {
    ...$json,
    document_title: `GP-WF-005 - YouTube Transcript Cleaner - ${date}`,
    document_body: body
  }
}];
